  SparkLoggingEvent_CL
  | where log_logger_s == "PDM_CAEX" and Message has "MINECARE"
  | order by TimeGenerated desc 
  | take 1
};
let distpatch = view () {
  SparkLoggingEvent_CL
  | where log_logger_s == "PDM_CAEX" and Message has "DISPATCH"
  | order by TimeGenerated desc 
  | take 1
};
