let ventana = 5m;

// ===== FUNCIÓN REUSABLE =====
let evaluar_prediccion = (patron:string, recomendacion:string) {
    ContainerAppConsoleLogs_CL
    | where TimeGenerated > ago(ventana)
    | where ContainerGroupName_s startswith "mlp-uat-caj-svfn-job02"
    | where Log_s contains patron
    | extend msg = tostring(parse_json(Log_s).mensaje)
    | extend valor_str = extract(@"(-?\d+\.?\d*)$", 1, msg)
    | extend valor = todouble(valor_str)
    | top 1 by TimeGenerated desc
    // ============================
    // DETECCIÓN DE ANOMALÍAS (INTERNAS)
    // ============================
    | extend Anomalia = 
        valor_str == "" or
        isnull(valor_str) or
        valor_str == "NaN" or
        valor_str == "Infinity" or
        valor_str == "-Infinity" or
        isnull(valor)
    // ============================
    // ESTADO FINAL
    // ============================
    | extend Estado = iff(
        Anomalia or valor <= 0 or valor >= 15000,
        "Alertar",
        "No Alertar"
    )
    | project Recomendacion = recomendacion, Valor = valor, Estado
};

// ===== USO DE LA FUNCIÓN =====
let tph    = evaluar_prediccion("tph prediction",      "TPH");
let concol = evaluar_prediccion("concol prediction",   "ConCol");
let flow   = evaluar_prediccion("flow prediction",     "Predicción Flujo NaSH");

// ===== UNION + COLORES + FALLBACK =====
let resultados = union tph, concol, flow;

resultados
// Fallback: si no hubo datos para alguna recomendación en la ventana, la marcamos como "No Alertar"
| union (
    datatable(Recomendacion:string, Valor:real, Estado:string) [
        "TPH",                 real(null), "No Alertar",
        "ConCol",              real(null), "No Alertar",
        "Predicción Flujo NaSH", real(null), "No Alertar"
    ]
)
// Preferimos: 2 = alerta real, 1 = dato real sin alerta, 0 = fallback sin datos
| extend _pref = iif(Estado == "Alertar", 2, iif(isnotnull(Valor), 1, 0))
| summarize arg_max(_pref, *) by Recomendacion
| extend Color = iif(Estado == "Alertar", "#FDE2E2", "#EAF4EA")
| project Recomendacion, Valor, Estado, Color

