// =====================================
// ALERTA + COLOR + FALLBACK POR DESCRIPCIÓN
// =====================================

// Último registro real por cada descripción (si existe)
let ultimos_reales = 
    format_tables
    | summarize arg_max(ultimo_timestamp_fuente, *) by descripcion;

// Fallback: si una descripción no tiene registros, igual queremos verla como "No Alertar" (verde)
let fallback =
    datatable(descripcion:string, fuente:string, ultimo_timestamp_fuente:datetime, alertar:string, script_ejecutado:string)
    [
        "Datos Tags",            "Not Pii",        datetime(null), "false", "",
        "Datos 52 peaks",        "Archivo Manual", datetime(null), "false", "",
        "Datos threshold",       "Archivo Manual", datetime(null), "false", "",
        "Datos input",           "Archivo Manual", datetime(null), "false", "",
        "Datos source contants", "Archivo Manual", datetime(null), "false", ""
    ];

// Unimos "reales" + fallback y nos quedamos con el mejor por descripción (prefiere real sobre fallback)
union ultimos_reales, fallback
| extend _pref = iif(isnull(ultimo_timestamp_fuente), 0, 1)
| summarize arg_max(_pref, *) by descripcion
// Traemos umbral por descripción (minutos)
| join kind=leftouter (umbrales_por_descripcion) on descripcion
| extend umbral_minutos = iif(isnull(umbral_minutos), 60, umbral_minutos)
// Diferencia en minutos respecto de ahora (solo para filas reales)
| extend Diferencia_Minutos = datetime_diff('minute', now(), ultimo_timestamp_fuente)
// Estado final:
// - Si no hay timestamp (fila de fallback) -> No Alertar
// - Si el dato es más viejo que el umbral o el JSON trae alert=true -> Alertar
// - En otro caso -> No Alertar
| extend Estado = iif(
    isnull(ultimo_timestamp_fuente),
    "No Alertar",
    iif(Diferencia_Minutos > umbral_minutos or tolower(alertar) == "true", "Alertar", "No Alertar")
)
// Color igual que en los otros casos
| extend Color = iif(Estado == "Alertar", "#FDE2E2", "#EAF4EA")
| project  Estado, Color

