    | extend Estado = iff(Errores >= 1, "Alertar", "No Alertar")
    | extend Color  = iif(Estado == "Alertar", "#FDE2E2", "#EAF4EA")
    | project Tipo = "GLOBAL", Nombre = "Estado_global_SSAG", Estado, Color;

